export function createDefaultCp932SjisEncoder(replacement: number = 0x003f): EncodeSjisFn {
  return (text: string): Uint16Array => {
    const out = new Uint16Array(text.length);
    for (let i = 0; i < text.length; i += 1) {
      const ch = text[i];
      const mapped = CP932_UNICODE_TO_SJIS[ch];
      if (typeof mapped === "number") {
        out[i] = mapped & 0xffff;
      } else {
        out[i] = replacement;
      }
    }
    return out;
  };
}
